package com.revizeus.app

import android.content.Context
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.ImageView
import android.widget.TextView
import androidx.recyclerview.widget.RecyclerView
import org.json.JSONObject

class AccountCardAdapter(
    private val context: Context,
    private val accounts: List<AccountRegistry.AccountCache>,
    private val activeUid: String,
    private val onAccountSelected: (AccountRegistry.AccountCache) -> Unit
) : RecyclerView.Adapter<AccountCardAdapter.CardViewHolder>() {

    inner class CardViewHolder(itemView: View) : RecyclerView.ViewHolder(itemView) {
        val ivAvatar: ImageView = itemView.findViewById(R.id.ivCardAvatar)
        val tvPseudo: TextView = itemView.findViewById(R.id.tvCardPseudo)
        val tvLevel: TextView = itemView.findViewById(R.id.tvCardLevel)
        val tvEmail: TextView = itemView.findViewById(R.id.tvCardEmail)
        val tvPlayTime: TextView = itemView.findViewById(R.id.tvCardPlayTime)
        val tvSavoirs: TextView = itemView.findViewById(R.id.tvCardSavoirs)
        val tvEclats: TextView = itemView.findViewById(R.id.tvCardEclats)
        val tvAmbroisie: TextView = itemView.findViewById(R.id.tvCardAmbroisie)
        val tvFragmentZeus: TextView = itemView.findViewById(R.id.tvFragmentZeus)
        val tvFragmentAthena: TextView = itemView.findViewById(R.id.tvFragmentAthena)
        val tvFragmentPoseidon: TextView = itemView.findViewById(R.id.tvFragmentPoseidon)
        val tvFragmentAres: TextView = itemView.findViewById(R.id.tvFragmentAres)
        val tvFragmentAphrodite: TextView = itemView.findViewById(R.id.tvFragmentAphrodite)
        val tvFragmentHermes: TextView = itemView.findViewById(R.id.tvFragmentHermes)
        val tvFragmentDemeter: TextView = itemView.findViewById(R.id.tvFragmentDemeter)
        val tvFragmentHephaistos: TextView = itemView.findViewById(R.id.tvFragmentHephaistos)
        val tvFragmentApollon: TextView = itemView.findViewById(R.id.tvFragmentApollon)
        val tvFragmentPromethee: TextView = itemView.findViewById(R.id.tvFragmentPromethee)
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): CardViewHolder {
        return CardViewHolder(LayoutInflater.from(context).inflate(R.layout.item_account_card, parent, false))
    }

    override fun onBindViewHolder(holder: CardViewHolder, position: Int) {
        val account = accounts[position]

        val avatarResId = context.resources.getIdentifier(account.avatarResName, "drawable", context.packageName)
        holder.ivAvatar.setImageResource(if (avatarResId != 0) avatarResId else android.R.drawable.sym_def_app_icon)

        holder.tvPseudo.text = account.pseudo.ifBlank { "Héros" }
        holder.tvLevel.text = "LVL ${account.level}"

        val rememberedEmail = try {
            AccountRegistry.getRememberedAccountEmail(context, account.uid).trim()
        } catch (_: Exception) { "" }
        holder.tvEmail.text = if (rememberedEmail.isNotBlank()) rememberedEmail else "UID : ${account.uid}"

        holder.tvPlayTime.text = "⏱ ${AccountRegistry.formatPlayTime(account.totalPlayTimeSeconds)}"
        holder.tvSavoirs.text = "📚 ${account.totalCoursScanned} savoir" + if (account.totalCoursScanned > 1) "s" else ""
        holder.tvEclats.text = "${account.eclatsSavoir} Éclats de savoir"
        holder.tvAmbroisie.text = "${account.ambroisie} Ambroisie"

        val fragments = parseFragmentMap(account.fragmentDetailsJson)
        holder.tvFragmentZeus.text = fragments["zeus"].toString()
        holder.tvFragmentAthena.text = fragments["athena"].toString()
        holder.tvFragmentPoseidon.text = fragments["poseidon"].toString()
        holder.tvFragmentAres.text = fragments["ares"].toString()
        holder.tvFragmentAphrodite.text = fragments["aphrodite"].toString()
        holder.tvFragmentHermes.text = fragments["hermes"].toString()
        holder.tvFragmentDemeter.text = fragments["demeter"].toString()
        holder.tvFragmentHephaistos.text = fragments["hephaistos"].toString()
        holder.tvFragmentApollon.text = fragments["apollon"].toString()
        holder.tvFragmentPromethee.text = fragments["promethee"].toString()

        holder.itemView.setOnClickListener { onAccountSelected(account) }
    }

    override fun getItemCount(): Int = accounts.size

    private fun parseFragmentMap(raw: String): Map<String, Int> {
        val base = linkedMapOf(
            "zeus" to 0, "athena" to 0, "poseidon" to 0, "ares" to 0, "aphrodite" to 0,
            "hermes" to 0, "demeter" to 0, "hephaistos" to 0, "apollon" to 0, "promethee" to 0
        )
        return try {
            if (raw.isBlank()) return base
            val json = JSONObject(raw)
            val keys = json.keys()
            while (keys.hasNext()) {
                val key = keys.next()
                val mapped = mapFragmentKeyToGod(key)
                base[mapped] = (base[mapped] ?: 0) + json.optInt(key, 0).coerceAtLeast(0)
            }
            base
        } catch (_: Exception) { base }
    }

    private fun mapFragmentKeyToGod(rawKey: String): String {
        val key = rawKey.trim().lowercase()
        return when {
            "zeus" in key || "math" in key || "mathem" in key -> "zeus"
            "athena" in key || "fran" in key || "litter" in key || "gramma" in key -> "athena"
            "poseidon" in key || "svt" in key || "bio" in key || "vivant" in key -> "poseidon"
            "ares" in key || "hist" in key -> "ares"
            "aphrodite" in key || "art" in key || "musique" in key -> "aphrodite"
            "hermes" in key || "langue" in key || "anglais" in key || "espagnol" in key || "allemand" in key -> "hermes"
            "demeter" in key || "geo" in key || "géographie" in key -> "demeter"
            "hephaistos" in key || "phys" in key || "chim" in key -> "hephaistos"
            "apollon" in key || "philo" in key || "ses" in key -> "apollon"
            "promethee" in key || "projet" in key || "vie" in key -> "promethee"
            else -> "zeus"
        }
    }
}

package com.revizeus.app

import android.content.Context
import android.util.Log
import com.google.firebase.firestore.FieldValue
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.firestore.SetOptions
import java.security.MessageDigest
import java.security.SecureRandom

/**
 * AccountRecoveryManager — RéviZeus
 * ─────────────────────────────────────────────────────────────
 * OBJECTIF :
 * - Ajouter un vrai code de secours par compte Firebase (UID)
 * - Ne JAMAIS casser la logique actuelle 1 email = jusqu'à 3 héros
 * - Conserver la séparation :
 *      Firebase Auth = identité cloud
 *      Room         = gameplay local
 *      RecoveryCode = filet de sécurité compte
 *
 * ÉVOLUTION v2 :
 * - stockage local du code brut pour pouvoir le réafficher depuis les réglages
 * - drapeau "acknowledged" pour forcer l'affichage du popup tant que
 *   l'utilisateur n'a pas explicitement confirmé qu'il a bien conservé le code
 */
object AccountRecoveryManager {

    private const val PREFS_NAME = "ReviZeusRecovery"
    private const val KEY_HASH_PREFIX = "recovery_hash_"
    private const val KEY_HINT_PREFIX = "recovery_hint_"
    private const val KEY_EMAIL_PREFIX = "recovery_email_"
    private const val KEY_SYNC_AT_PREFIX = "recovery_sync_at_"
    private const val KEY_RAW_PREFIX = "recovery_raw_"
    private const val KEY_ACK_PREFIX = "recovery_ack_"

    private val secureRandom = SecureRandom()

    /**
     * Génère un code de secours lisible par l'utilisateur.
     *
     * Format choisi :
     * REVZ-ABCD-EFGH-IJKL
     */
    fun generateRecoveryCode(): String {
        val alphabet = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"
        fun block(size: Int): String = buildString {
            repeat(size) { append(alphabet[secureRandom.nextInt(alphabet.length)]) }
        }
        return "REVZ-${block(4)}-${block(4)}-${block(4)}"
    }

    /**
     * Normalise une saisie utilisateur.
     * On retire espaces et tirets parasites pour éviter les faux échecs.
     */
    fun normalizeRecoveryCode(raw: String): String {
        return raw
            .uppercase()
            .replace("\\s".toRegex(), "")
            .replace("-", "")
            .trim()
    }

    /**
     * Hash SHA-256 simple et stable.
     * Suffisant ici pour éviter de stocker le code brut dans Firestore.
     */
    fun hashRecoveryCode(raw: String): String {
        val normalized = normalizeRecoveryCode(raw)
        val bytes = MessageDigest.getInstance("SHA-256").digest(normalized.toByteArray())
        return bytes.joinToString("") { "%02x".format(it) }
    }

    /**
     * Retourne un indice d'affichage non sensible.
     */
    fun buildHint(raw: String): String {
        val normalized = normalizeRecoveryCode(raw)
        return if (normalized.length >= 4) "••••-${normalized.takeLast(4)}" else "••••"
    }

    /**
     * Indique si un code de secours local existe déjà pour ce compte.
     */
    fun hasLocalRecoveryCode(context: Context, firebaseUid: String): Boolean {
        if (firebaseUid.isBlank()) return false
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        return prefs.getString(KEY_HASH_PREFIX + firebaseUid, "").orEmpty().isNotBlank()
    }

    /**
     * Retourne le code brut local si cet appareil le possède encore.
     */
    fun getLocalRecoveryCode(context: Context, firebaseUid: String): String {
        if (firebaseUid.isBlank()) return ""
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        return prefs.getString(KEY_RAW_PREFIX + firebaseUid, "").orEmpty()
    }

    /**
     * Retourne l'indice local du code de secours.
     */
    fun getLocalRecoveryHint(context: Context, firebaseUid: String): String {
        if (firebaseUid.isBlank()) return ""
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        return prefs.getString(KEY_HINT_PREFIX + firebaseUid, "").orEmpty()
    }

    /**
     * Le popup a-t-il été explicitement validé par l'utilisateur ?
     */
    fun isRecoveryCodeAcknowledged(context: Context, firebaseUid: String): Boolean {
        if (firebaseUid.isBlank()) return false
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        return prefs.getBoolean(KEY_ACK_PREFIX + firebaseUid, false)
    }

    /**
     * Marque le code comme bien conservé par l'utilisateur.
     */
    fun markRecoveryCodeAcknowledged(context: Context, firebaseUid: String) {
        if (firebaseUid.isBlank()) return
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        prefs.edit().putBoolean(KEY_ACK_PREFIX + firebaseUid, true).apply()
    }

    /**
     * Réinitialise l'acquittement si un futur flow exige de remontrer le code.
     */
    fun clearRecoveryCodeAcknowledged(context: Context, firebaseUid: String) {
        if (firebaseUid.isBlank()) return
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        prefs.edit().putBoolean(KEY_ACK_PREFIX + firebaseUid, false).apply()
    }

    /**
     * Vérifie localement un code saisi contre le compte indiqué.
     */
    fun verifyLocalRecoveryCode(context: Context, firebaseUid: String, rawCode: String): Boolean {
        if (firebaseUid.isBlank()) return false
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        val savedHash = prefs.getString(KEY_HASH_PREFIX + firebaseUid, "").orEmpty()
        if (savedHash.isBlank()) return false
        return savedHash == hashRecoveryCode(rawCode)
    }

    /**
     * Sauvegarde :
     * - localement dans SharedPreferences
     * - puis dans Firestore sous users/{uid}
     *
     * IMPORTANT :
     * - le brut reste seulement local à l'appareil
     * - Firestore ne reçoit que le hash + l'indice
     * - un nouveau code doit être explicitement revalidé par l'utilisateur
     */
    fun saveRecoveryCode(
        context: Context,
        firebaseUid: String,
        accountEmail: String,
        rawCode: String,
        onSuccess: () -> Unit,
        onError: (String) -> Unit
    ) {
        if (firebaseUid.isBlank()) {
            onError("UID Firebase introuvable pour enregistrer le code de secours.")
            return
        }

        val hash = hashRecoveryCode(rawCode)
        val hint = buildHint(rawCode)

        try {
            val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
            prefs.edit()
                .putString(KEY_HASH_PREFIX + firebaseUid, hash)
                .putString(KEY_HINT_PREFIX + firebaseUid, hint)
                .putString(KEY_EMAIL_PREFIX + firebaseUid, accountEmail)
                .putString(KEY_RAW_PREFIX + firebaseUid, rawCode)
                .putBoolean(KEY_ACK_PREFIX + firebaseUid, false)
                .putLong(KEY_SYNC_AT_PREFIX + firebaseUid, System.currentTimeMillis())
                .apply()
        } catch (e: Exception) {
            Log.e("RecoveryCode", "Erreur sauvegarde locale", e)
            onError("Le code a été généré, mais sa sauvegarde locale a échoué.")
            return
        }

        val payload = hashMapOf(
            "recoveryEnabled" to true,
            "recoveryCodeHash" to hash,
            "recoveryCodeHint" to hint,
            "recoveryEmailSnapshot" to accountEmail,
            "recoveryUpdatedAt" to FieldValue.serverTimestamp()
        )

        FirebaseFirestore.getInstance()
            .collection("users")
            .document(firebaseUid)
            .set(payload, SetOptions.merge())
            .addOnSuccessListener { onSuccess() }
            .addOnFailureListener { error ->
                Log.e("RecoveryCode", "Erreur sync Firestore", error)
                onError(error.localizedMessage ?: "Le code local a été créé, mais la synchronisation cloud a échoué.")
            }
    }
}

