package com.revizeus.app

/**
 * Transforme le snapshot joueur + la personnalité du dieu en bloc texte injecté dans
 * GeminiManager.adaptiveContextNote.
 *
 * Le format est volontairement textuel pour respecter ton architecture actuelle :
 * ton GeminiManager sait déjà exploiter adaptiveContextNote sans qu'on ait besoin
 * de casser ses signatures ni ses prompts de base.
 */
object AdaptiveContextFormatter {

    fun buildAdaptiveContextNote(
        snapshot: PlayerAdaptiveSnapshot,
        godId: String,
        dialogCategory: DialogCategory,
        triggerLabel: String,
        explicitGoal: String,
        extraInstructions: String? = null
    ): String {
        val personality = GodPersonalityEngine.get(godId)

        val templeBlock = if (snapshot.templeProgressByGod.isEmpty()) {
            "- progression temples : non fournie pour cette scène"
        } else {
            buildString {
                appendLine("- progression temples :")
                snapshot.templeProgressByGod.entries.sortedBy { it.key }.forEach { entry ->
                    appendLine("  • ${entry.key} = niveau ${entry.value}/10")
                }
            }.trimEnd()
        }

        val equipmentBlock = buildString {
            appendLine("- objets équipés : ${snapshot.equippedItems.joinToString(", ").ifBlank { "aucun" }}")
            appendLine("- artefacts équipés : ${snapshot.equippedArtifacts.joinToString(", ").ifBlank { "aucun" }}")
        }.trimEnd()

        val weaknessesBlock = buildString {
            appendLine("- faiblesses récentes : ${snapshot.recentErrorSubjects.joinToString(", ").ifBlank { "non détectées" }}")
            appendLine("- sujets faibles : ${snapshot.weakTopics.joinToString(", ").ifBlank { "non détectés" }}")
            appendLine("- sujets forts : ${snapshot.strongTopics.joinToString(", ").ifBlank { "non détectés" }}")
        }.trimEnd()

        val futureParamsBlock = if (snapshot.futureParams.isEmpty()) {
            "- paramètres futurs : aucun"
        } else {
            buildString {
                appendLine("- paramètres futurs :")
                snapshot.futureParams.toSortedMap().forEach { (key, value) ->
                    appendLine("  • $key = $value")
                }
            }.trimEnd()
        }

        return """
            CONTEXTE JOUEUR EXTENSIBLE — RÉVIZEUS
            - pseudo : ${snapshot.pseudo}
            - âge : ${snapshot.age}
            - classe : ${snapshot.classLevel}
            - humeur : ${snapshot.mood}
            - niveau : ${snapshot.level}
            - rang : ${snapshot.rank}
            - titre équipé : ${snapshot.titleEquipped}
            - pattern cognitif : ${snapshot.cognitivePattern}
            - précision logique : ${formatFloat(snapshot.logicalPrecisionScore)}
            - fréquence des erreurs récurrentes : ${formatFloat(snapshot.errorPatternFrequency)}
            - indice de fatigue : ${formatFloat(snapshot.fatigueIndex)}
            - susceptibilité aux biais : ${formatFloat(snapshot.biasSusceptibility)}
            - taux de décroissance mémorielle : ${formatFloat(snapshot.retentionDecayRate)}
            - coefficient d'adaptabilité : ${formatFloat(snapshot.adaptabilityCoefficient)}
            - quiz totaux : ${snapshot.totalQuizDone}
            - série de victoires : ${snapshot.winStreak}
            - série quotidienne : ${snapshot.dayStreak}
            - XP totale gagnée : ${snapshot.totalXpEarned}
            - éclats de savoir : ${snapshot.eclatsSavoir}
            - ambroisie : ${snapshot.ambroisie}
            - matière courante : ${snapshot.currentSubject ?: "non précisée"}
            - topic courant : ${snapshot.currentTopic ?: "non précisé"}
            - cours courant : ${snapshot.currentCourseTitle ?: "non précisé"}
            - question courante : ${snapshot.currentQuestionText ?: "non précisée"}
            - score récent : ${snapshot.latestScorePercent?.let { "$it%" } ?: "non fourni"}
            - étoiles récentes : ${snapshot.latestStars ?: "non fournies"}
            - taux de réussite récent : ${snapshot.recentSuccessRate?.let { "${formatFloat(it)}" } ?: "non calculé"}
            - temps de réponse moyen récent : ${snapshot.recentAverageResponseTimeMs?.let { "$it ms" } ?: "non calculé"}
            - fragments matière courante : ${snapshot.currentSubjectFragmentCount ?: "non calculé"}
            - issue explicite de la scène : ${snapshot.explicitOutcome ?: "non précisée"}
            - étape aventure : ${snapshot.adventureStep ?: "non fournie"}

            $templeBlock

            $equipmentBlock

            $weaknessesBlock

            PERSONNALITÉ DIVINE CIBLE
            - dieu : ${personality.displayName}
            - identité de ton : ${personality.toneIdentity}
            - style pédagogique : ${personality.pedagogyStyle}
            - style d'humour : ${personality.humorStyle}
            - niveau d'autorité : ${personality.authorityLevel}/10
            - rythme de phrase : ${personality.preferredSentenceRhythm}
            - niveau de vocabulaire : ${personality.vocabularyLevel}
            - style émotionnel : ${personality.emotionalStyle}
            - style de correction : ${personality.correctionStyle}
            - style de défi : ${personality.challengeStyle}
            - style de récompense : ${personality.rewardStyle}
            - style de fatigue divine : ${personality.fatigueStyle}
            - dérives interdites : ${personality.forbiddenDrifts.joinToString(", ")}

            CADRE DE LA SCÈNE
            - catégorie de dialogue : ${dialogCategory.name}
            - déclencheur : $triggerLabel
            - objectif explicite : $explicitGoal

            DIRECTIVES CRITIQUES POUR LA GÉNÉRATION
            - génère un vrai texte contextuel, pas une phrase générique interchangeable ;
            - exploite l'âge, la classe, l'humeur, la performance, la fatigue et la progression si cela aide réellement ;
            - n'invente pas de données absentes ;
            - reste utilisable dans un dialogue RPG mobile ;
            - si la scène est mineure, reste bref ;
            - si la scène est pédagogique, sois utile avant d'être spectaculaire ;
            - conserve l'identité du dieu sans caricature ;
            - la réponse doit pouvoir être affichée lettre par lettre ;
            - le champ mnemo doit être vraiment utile ;
            - suggestedAction doit proposer une action concrète pour le joueur.

            $futureParamsBlock

            INSTRUCTIONS ADDITIONNELLES
            ${extraInstructions?.ifBlank { "- aucune" } ?: "- aucune"}
        """.trimIndent()
    }

    private fun formatFloat(value: Float): String {
        return String.format(java.util.Locale.US, "%.2f", value)
    }
}

package com.revizeus.app

import android.content.Context

/**
 * ═══════════════════════════════════════════════════════════════
 * ADAPTIVE DIALOGUE ENGINE — Fusion Dieu + Joueur + Contexte
 * ═══════════════════════════════════════════════════════════════
 *
 * Rôle :
 * - Transformer un message brut en message incarné et adaptatif.
 * - Produire un bloc de contexte réutilisable pour GeminiManager.
 * - Construire des DialogRPGConfig cohérents sans imposer de refonte des écrans.
 *
 * Important :
 * - Le moteur reste volontairement conservateur sur les textes locaux.
 * - Il enrichit sans casser le sens métier fourni par les Activities.
 * - Il prépare le terrain pour les futures invocations IA plus profondes.
 * ═══════════════════════════════════════════════════════════════
 */
object AdaptiveDialogueEngine {

    data class AdaptiveDialogRequest(
        val godId: String,
        val category: DialogCategory,
        val rawMessage: String,
        val title: String? = null,
        val additionalLabel: String? = null,
        val additionalText: String? = null,
        val button1Label: String = "COMPRIS ⚡",
        val button1Action: (() -> Unit)? = null,
        val button2Label: String? = null,
        val button2Action: (() -> Unit)? = null,
        val button3Label: String? = null,
        val button3Action: (() -> Unit)? = null,
        val cancelable: Boolean = true,
        val tapToSkipTypewriter: Boolean = true,
        val onDismiss: (() -> Unit)? = null
    )

    fun buildAdaptiveConfig(
        context: Context,
        request: AdaptiveDialogRequest,
        playerContext: PlayerContextResolver.PlayerDialogueContext = PlayerContextResolver.resolveLightweight(context)
    ): DialogRPGConfig {
        val normalizedGodId = GodPersonalityEngine.normalizeGodId(request.godId)
        val personality = GodPersonalityEngine.getPersonality(normalizedGodId)
        val adaptiveMessage = GodPersonalityEngine.createLocalAdaptiveMessage(
            godId = normalizedGodId,
            rawMessage = request.rawMessage,
            playerContext = playerContext,
            category = request.category
        )

        val speed = computeTypewriterSpeed(
            category = request.category,
            playerContext = playerContext,
            personality = personality
        )

        return DialogRPGConfig(
            mainText = adaptiveMessage,
            godId = normalizedGodId,
            title = request.title,
            additionalLabel = request.additionalLabel,
            additionalText = request.additionalText,
            category = request.category,
            button1Label = request.button1Label,
            button1Action = request.button1Action,
            button2Label = request.button2Label,
            button2Action = request.button2Action,
            button3Label = request.button3Label,
            button3Action = request.button3Action,
            cancelable = request.cancelable,
            tapToSkipTypewriter = request.tapToSkipTypewriter,
            typewriterSpeed = speed,
            onDismiss = request.onDismiss
        )
    }

    fun buildAdaptivePromptNote(
        godId: String,
        dialogContext: DialogContext,
        playerContext: PlayerContextResolver.PlayerDialogueContext,
        rawIntent: String,
        rawMessage: String
    ): String {
        val personality = GodPersonalityEngine.getPersonality(godId)
        return """
            PROFIL DIVIN :
            - dieu : ${personality.displayName}
            - rôle pédagogique : ${personality.pedagogicalRole}
            - tonalité : ${personality.toneTag}
            - rythme : ${personality.speechRhythm}
            - sévérité : ${personality.strictness}/10
            - chaleur : ${personality.warmth}/10
            - poésie : ${personality.poeticLevel}/10
            - questions guidées : ${if (personality.usesQuestions) "oui" else "non"}

            PROFIL JOUEUR :
            - pseudo : ${playerContext.pseudo}
            - âge : ${playerContext.age}
            - classe : ${playerContext.classLevel}
            - humeur : ${playerContext.mood}
            - niveau : ${playerContext.level}
            - rang : ${playerContext.rank}
            - point faible dominant : ${playerContext.dominantWeakness}
            - taux de réussite récent : ${(playerContext.recentSuccessRate * 100f).toInt()}%
            - temps de réponse moyen : ${playerContext.averageResponseTimeMs} ms
            - fatigue : ${"%.2f".format(playerContext.fatigueIndex)}
            - mode doux : ${playerContext.needsGentleMode}
            - mode défi : ${playerContext.needsChallengeMode}

            CONTEXTE DE LA SCÈNE :
            - contexte : $dialogContext
            - intention brute : $rawIntent
            - message métier à respecter : $rawMessage

            CONTRAINTES DE SORTIE :
            - la réponse doit rester brève, typewriter-compatible et lisible en dialogue RPG ;
            - elle doit conserver le sens réel du message métier ;
            - elle doit être incarnée par ${personality.displayName} ;
            - aucun jargon technique brut ne doit être exposé ;
            - la dernière phrase doit idéalement être mémorisable ;
            - ${GodPersonalityEngine.buildSystemInstruction(godId)}
        """.trimIndent()
    }

    private fun computeTypewriterSpeed(
        category: DialogCategory,
        playerContext: PlayerContextResolver.PlayerDialogueContext,
        personality: GodPersonalityEngine.GodPersonality
    ): Long {
        var speed = 35L

        if (playerContext.needsGentleMode) {
            speed += 6L
        }
        if (playerContext.needsChallengeMode) {
            speed -= 4L
        }
        if (personality.speechRhythm.contains("rapide", ignoreCase = true)) {
            speed -= 3L
        }
        if (personality.speechRhythm.contains("posé", ignoreCase = true) || personality.speechRhythm.contains("doux", ignoreCase = true)) {
            speed += 3L
        }
        if (category == DialogCategory.REWARD) {
            speed = (speed - 2L).coerceAtLeast(24L)
        }
        if (category == DialogCategory.ERROR_TECHNICAL || category == DialogCategory.CONFIRMATION) {
            speed = (speed + 2L).coerceAtMost(48L)
        }

        return speed.coerceIn(24L, 48L)
    }
}

package com.revizeus.app

import android.content.Context
import com.revizeus.app.models.AppDatabase
import com.revizeus.app.models.UserAnalytics
import com.revizeus.app.models.UserProfile
import com.revizeus.app.models.UserSkillProfile
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

object AdaptiveLearningContextResolver {

    suspend fun resolve(
        context: Context,
        subject: String,
        fallbackAge: Int = 15,
        fallbackClassLevel: String = "Terminale",
        fallbackMood: String = "Prêt"
    ): AdaptiveLearningContext = withContext(Dispatchers.IO) {
        val db = AppDatabase.getDatabase(context)
        val dao = db.iAristoteDao()
        val profile = try {
            dao.getUserProfile() ?: UserProfile(
                id = 1,
                age = fallbackAge,
                classLevel = fallbackClassLevel,
                mood = fallbackMood,
                xp = 0,
                streak = 0,
                cognitivePattern = "Standard"
            )
        } catch (_: Exception) {
            UserProfile(
                id = 1,
                age = fallbackAge,
                classLevel = fallbackClassLevel,
                mood = fallbackMood,
                xp = 0,
                streak = 0,
                cognitivePattern = "Standard"
            )
        }

        val analyticsBySubject = try {
            db.userAnalyticsDao().getBySubject(profile.id, subject)
        } catch (_: Exception) {
            emptyList()
        }

        val analytics = if (analyticsBySubject.isNotEmpty()) {
            analyticsBySubject.take(40)
        } else {
            try {
                db.userAnalyticsDao().getRecent(profile.id, 40)
            } catch (_: Exception) {
                emptyList()
            }
        }

        val skillProfiles = try {
            db.userSkillProfileDao().getAllByUser(profile.id)
                .filter { it.subject.equals(subject, ignoreCase = true) }
        } catch (_: Exception) {
            emptyList()
        }

        buildContext(profile, subject, analytics, skillProfiles)
    }

    private fun buildContext(
        profile: UserProfile,
        subject: String,
        analytics: List<UserAnalytics>,
        skillProfiles: List<UserSkillProfile>
    ): AdaptiveLearningContext {
        val successRate = if (analytics.isNotEmpty()) {
            ((analytics.count { it.isCorrect }.toFloat() / analytics.size.toFloat()) * 100f).toInt()
        } else {
            65
        }

        val avgResponseTime = analytics
            .map { it.responseTime.coerceAtLeast(0L) }
            .average()
            .toLong()
            .coerceAtLeast(3200L)

        val weakTopics = skillProfiles
            .sortedWith(compareBy<UserSkillProfile> { !it.needsReview }.thenBy { it.masteryLevel })
            .take(3)
            .map { it.topic }
            .filter { it.isNotBlank() }

        val recentMistakePattern = detectMistakePattern(analytics)
        val performanceBand = when {
            successRate >= 86 -> "solide"
            successRate >= 65 -> "intermédiaire"
            else -> "fragile"
        }

        val fragilityBand = when {
            profile.mood.contains("stress", ignoreCase = true) -> "élevée"
            profile.mood.contains("fatigu", ignoreCase = true) -> "moyenne à élevée"
            successRate < 55 -> "élevée"
            successRate < 70 -> "moyenne"
            else -> "faible"
        }

        val pacingBand = when {
            avgResponseTime >= 9000L -> "très progressif"
            avgResponseTime >= 6000L -> "progressif"
            avgResponseTime >= 4200L -> "standard"
            else -> "dynamique"
        }

        val isYoung = profile.age <= 11
        val isCollege = profile.age in 12..15
        val isLyceeOrAbove = profile.age >= 16

        val summaryStyle = when {
            isYoung || fragilityBand == "élevée" -> "phrases courtes, idées très découpées, vocabulaire simple"
            isCollege -> "résumé structuré, concret, avec idées-clés clairement séparées"
            else -> "résumé scolaire dense mais lisible, plus rigoureux et précis"
        }

        val questionStyle = when {
            isYoung || successRate < 55 -> "questions courtes, distracteurs très distincts, consignes très lisibles"
            fragilityBand == "élevée" -> "questions nettes, sans ambiguïté inutile, une idée par item"
            isLyceeOrAbove && successRate >= 80 -> "questions un peu plus exigeantes, distracteurs crédibles et plus proches"
            else -> "questions scolaires équilibrées, claires et progressives"
        }

        val correctionStyle = when {
            isYoung -> "maïeutique très guidée, une seule idée à la fois, ton rassurant"
            fragilityBand == "élevée" -> "très rassurant, reformulation courte, guidage explicite"
            successRate >= 80 -> "plus exigeant, mais toujours bref et précis"
            else -> "guidé, structuré et concret"
        }

        val recommendedAction = when {
            weakTopics.isNotEmpty() -> "Revenir sur ${weakTopics.first()} avant un nouveau quiz long"
            successRate < 55 -> "Refaire un quiz court sur une seule notion"
            successRate < 75 -> "Relire le résumé puis refaire un entraînement ciblé"
            else -> "Passer à une version légèrement plus exigeante"
        }

        return AdaptiveLearningContext(
            age = profile.age,
            classLevel = profile.classLevel,
            mood = profile.mood,
            subject = subject,
            successRate = successRate,
            averageResponseTimeMs = avgResponseTime,
            weakTopics = weakTopics,
            performanceBand = performanceBand,
            fragilityBand = fragilityBand,
            pacingBand = pacingBand,
            summaryStyle = summaryStyle,
            questionStyle = questionStyle,
            correctionStyle = correctionStyle,
            recommendedAction = recommendedAction,
            recentMistakePattern = recentMistakePattern
        )
    }

    private fun detectMistakePattern(analytics: List<UserAnalytics>): String {
        if (analytics.isEmpty()) return "Aucun historique exploitable"
        val wrong = analytics.filter { !it.isCorrect }
        if (wrong.isEmpty()) return "Performance récente propre, erreurs rares"
        val latest = wrong.take(8)
        val veryFastWrong = latest.count { it.responseTime in 1..2200L }
        val slowWrong = latest.count { it.responseTime >= 7000L }
        return when {
            veryFastWrong >= 3 -> "réponses trop rapides, probable précipitation"
            slowWrong >= 3 -> "hésitation importante, notion encore instable"
            else -> "erreurs diffuses, besoin de consolidation progressive"
        }
    }
}

