                }
            }
        } else {
            scope.launch {
                try {
                    if (!isTypewriterSessionUsable(textView, chibiView, key, sessionToken)) {
                        return@launch
                    }

                    textView.text = ""

                    for (i in text.indices) {
                        if (!isActive || !isTypewriterSessionUsable(textView, chibiView, key, sessionToken)) {
                            break
