                    R.id.chipBouclier -> "ARTEFACTS"
                    R.id.chipArme -> "ÉQUIPEMENTS"
                    R.id.chipArtefact -> "OBJETS"
                    R.id.chipParchemin -> "RELIQUES"
                    else -> "FRAGMENTS"
