        private const val PREF_HERO_CREATION_MODE = "HERO_CREATION_MODE"
        private const val HERO_CREATION_MODE_NEW_ACCOUNT = "new_account"
        private const val HERO_CREATION_MODE_EXISTING_ACCOUNT = "existing_account"
    }

