object QuizTimerManager {

    /**
     * NOUVELLE RÈGLE DEMANDÉE :
     * 0 - 10 ans → 30s
     * 11 - 20 ans → 25s
     * 21+ → 20s
     *
     * Ancienne règle remplacée proprement.
