            }
            currentScanLoopResId = resId
        } catch (e: Exception) {
            Log.w(TAG, "playLoopingScan failed for resId=$resId", e)
        }
    }

    /**
     * Arrête uniquement le scan loop secondaire.
     */
    fun stopLoopingScan() {
        try {
            scanLoopPlayer?.apply {
                if (isPlaying) stop()
