            }
        } catch (e: Exception) {
            Log.w(TAG, "stopLoopingScan failed", e)
        }
        scanLoopPlayer = null
        currentScanLoopResId = -1
    }

    /**
     * Ajuste le volume du canal scan secondaire.
     */
    fun setScanLoopVolume(volume: Float) {
        currentScanLoopVol = volume.coerceIn(0f, 1f)
