                val finalPrompt = """
                    $multiTypePrompt

                    $targetingContext
                """.trimIndent()

                Log.d(TAG, "Appel Gemini ${callIndex + 1}/$MAX_GEMINI_CALLS")

                val geminiResponse = try {
